#include <iostream>
#include <string>
using namespace std;

int main()
{
    int score = 78;
    string grade;

    if (score >= 90)
    {
        grade = "AA";
    }
    else if (score >= 70)
    {
        grade = "BA";
    }
    else if (score >= 50)
    {
        grade = "CC";
    }
    else
    {
        grade = "FF";
    }

    cout << "Not: " << score << " -> Harf notu: " << grade << endl;

    // Switch ornegi
    int day = 3;
    string dayName;

    switch (day)
    {
        case 1:
            dayName = "Pazartesi";
            break;
        case 2:
            dayName = "Sali";
            break;
        case 3:
            dayName = "Carsamba";
            break;
        default:
            dayName = "Bilinmeyen gun";
            break;
    }

    cout << "Gun: " << dayName << endl;

    // Ternary operator
    int number = 7;
    string parity = (number % 2 == 0) ? "Cift" : "Tek";
    cout << number << " sayisi " << parity << endl;

    return 0;
}
